1	/**
2	 * Scheduled Tasks REST API
3	 *
4	 * GET    /api/scheduled-tasks           — 获取任务列表
5	 * POST   /api/scheduled-tasks           — 创建任务
6	 * GET    /api/scheduled-tasks/runs      — 获取所有任务的最近执行记录
7	 * GET    /api/scheduled-tasks/:id/runs  — 获取指定任务的执行记录
8	 * POST   /api/scheduled-tasks/:id/run   — 立即执行指定任务
9	 * PUT    /api/scheduled-tasks/:id       — 更新任务
10	 * DELETE /api/scheduled-tasks/:id       — 删除任务
11	 */
12	
13	import { CronService, type CronTask } from '../services/cronService.js'
14	import { cronScheduler } from '../services/cronScheduler.js'
15	import { ApiError, errorResponse } from '../middleware/errorHandler.js'
16	
17	const cronService = new CronService()
18	
19	export async function handleScheduledTasksApi(
20	  req: Request,
21	  _url: URL,
22	  segments: string[],
23	): Promise<Response> {
24	  try {
25	    const method = req.method
26	    const taskId = segments[2] // /api/scheduled-tasks/:id  or "runs"
27	    const subResource = segments[3] // /api/scheduled-tasks/:id/runs
28	
29	    // ── GET /api/scheduled-tasks/runs ────────────────────────────────────
30	    if (method === 'GET' && taskId === 'runs') {
31	      const url = new URL(req.url)
32	      const limit = parseInt(url.searchParams.get('limit') || '50', 10)
33	      const runs = await cronScheduler.getRecentRuns(limit)
34	      return Response.json({ runs })
35	    }
36	
37	    // ── GET /api/scheduled-tasks/:id/runs ────────────────────────────────
38	    if (method === 'GET' && taskId && subResource === 'runs') {
39	      const runs = await cronScheduler.getTaskRuns(taskId)
40	      return Response.json({ runs })
41	    }
42	
43	    // ── GET /api/scheduled-tasks ──────────────────────────────────────────
44	    if (method === 'GET' && !taskId) {
45	      const tasks = await cronService.listTasks()
46	      return Response.json({ tasks })
47	    }
48	
49	    // ── POST /api/scheduled-tasks ─────────────────────────────────────────
50	    if (method === 'POST' && !taskId) {
51	      const body = await parseJsonBody(req)
52	      const task = await cronService.createTask({
53	        name: body.name as string | undefined,
54	        description: body.description as string | undefined,
55	        cron: body.cron as string,
56	        prompt: body.prompt as string,
57	        enabled: body.enabled !== undefined ? (body.enabled as boolean) : undefined,
58	        recurring: body.recurring as boolean | undefined,
59	        permanent: body.permanent as boolean | undefined,
60	        permissionMode: body.permissionMode as string | undefined,
61	        model: body.model as string | undefined,
62	        folderPath: body.folderPath as string | undefined,
63	        useWorktree: body.useWorktree as boolean | undefined,
64	        notification: body.notification as CronTask['notification'],
65	      })
66	      return Response.json({ task }, { status: 201 })
67	    }
68	
69	    // ── POST /api/scheduled-tasks/:id/run ──────────────────────────────────
70	    // Fire-and-forget: start execution in background, return immediately.
71	    // The frontend polls GET /:id/runs to track progress.
72	    if (method === 'POST' && taskId && subResource === 'run') {
73	      const tasks = await cronService.listTasks()
74	      const task = tasks.find((t) => t.id === taskId)
75	      if (!task) throw ApiError.notFound(`Task ${taskId} not found`)
76	      cronScheduler.executeTask(task, { createSession: true }).catch((err) => {
77	        console.error(`[ScheduledTasks] Manual run failed for task ${taskId}:`, err)
78	      })
79	      // Small delay to let appendRun() write the "running" entry to disk
80	      await new Promise((r) => setTimeout(r, 200))
81	      return Response.json({ ok: true })
82	    }
83	
84	    // ── PUT /api/scheduled-tasks/:id ──────────────────────────────────────
85	    if (method === 'PUT' && taskId && !subResource) {
86	      const body = await parseJsonBody(req)
87	      const task = await cronService.updateTask(taskId, body)
88	      return Response.json({ task })
89	    }
90	
91	    // ── DELETE /api/scheduled-tasks/:id ───────────────────────────────────
92	    if (method === 'DELETE' && taskId && !subResource) {
93	      await cronService.deleteTask(taskId)
94	      return Response.json({ ok: true })
95	    }
96	
97	    throw new ApiError(
98	      405,
99	      `Method ${method} not allowed on /api/scheduled-tasks${taskId ? `/${taskId}` : ''}${subResource ? `/${subResource}` : ''}`,
100	      'METHOD_NOT_ALLOWED',
101	    )
102	  } catch (error) {
103	    return errorResponse(error)
104	  }
105	}
106	
107	// ─── Helpers ────────────────────────────────────────────────────────────────
108	
109	async function parseJsonBody(req: Request): Promise<Record<string, unknown>> {
110	  try {
111	    return (await req.json()) as Record<string, unknown>
112	  } catch {
113	    throw ApiError.badRequest('Invalid JSON body')
114	  }
115	}
116	

